# source_path = "abfss://drop-zone@cqldevdatahubdata.dfs.core.windows.net/AEMO_SourceCopy/"

dir_obj = {f.name:None for f in mssparkutils.fs.ls(source_path)}

full_paths = []

for year in dir_obj.keys():
    year_path = mssparkutils.fs.ls(f"{source_path}/{year}")
    dir_obj[year] = {f.name:None for f in year_path}

    for month in dir_obj[year].keys(): # Day
        day_path =  mssparkutils.fs.ls(f"{source_path}/{year}/{month}")
        dir_obj[year][month] = {f.name:None for f in day_path}
        print("File Path", day_path)
        for day in dir_obj[year][month].keys(): # Exact Date
            date_path =  mssparkutils.fs.ls(f"{source_path}/{year}/{month}/{day}")
            dir_obj[year][month][day] = {f.name:None for f in date_path}


            for date in dir_obj[year][month][day].keys(): # File Dir
                file_path = mssparkutils.fs.ls(f"{source_path}/{year}/{month}/{day}/{date}")
                dir_obj[year][month][day][date] = {f.name:None for f in file_path}
                for actual_file in dir_obj[year][month][day][date].keys():
                    actual_file_path = mssparkutils.fs.ls(f"{source_path}/{year}/{month}/{day}/{date}/{actual_file}")

                    for f in actual_file_path:
                        full_paths.append(f.path)

lookup = {}
for f in full_paths:
    file_content = spark.read.text(f,wholetext=True).collect()[0].value
    try:
        contents = extract_content(file_content)
        file_name,creation_date = extract_creation_date(contents,f)
        lookup[file_name] = creation_date
    except Exception as e: continue

from pyspark.sql.functions import udf
from pyspark.sql.types import StringType

@udf(StringType())
def lookup_creation_date(val):
    return lookup.get(val,"None")

df_bronze = df_bronze.withColumn("CreationDate", lookup_creation_date(df_bronze["FileName"]))
